{
  "chapter": {
    "description": "L’histoire de l’art raconte comment les humains ont donné forme à leurs idées, leurs croyances, leurs émotions et leur pouvoir à travers des images, des objets et des espaces. Elle aide à lire une peinture, une sculpture, un bâtiment ou une affiche comme une trace vivante d’une époque. On y croise des chefs-d’œuvre, mais aussi des gestes quotidiens, des inventions visuelles et des débats de société. Ce chapitre montre pourquoi l’art compte dans la vie ordinaire, dans les musées, dans les villes, dans les médias et dans les métiers qui travaillent avec les images.",
    "title": "Ce que raconte l’histoire de l’art"
  },
  "lessons": [
    {
      "description": "Ce que l’histoire de l’art cherche vraiment à expliquer : pas seulement ce qui est beau, mais pourquoi une image, un objet ou un lieu a été créé, par qui, pour qui et dans quel monde.",
      "title": "À quoi sert l’histoire de l’art"
    },
    {
      "description": "Une idée surprenante : une œuvre ne parle jamais toute seule. Sa couleur, sa taille, sa matière ou son emplacement peuvent changer complètement son sens.",
      "title": "Pourquoi une œuvre ne se lit pas comme un simple objet"
    },
    {
      "description": "Comment l’histoire de l’art apparaît dans la vie de tous les jours : musées, architecture, publicité, mode, cinéma, réseaux sociaux, monuments et espaces publics.",
      "title": "L’art autour de nous"
    },
    {
      "description": "Ce que font les personnes qui travaillent avec l’histoire de l’art : conservateurs, médiateurs, restaurateurs, commissaires d’exposition, critiques, chercheurs et professionnels du patrimoine.",
      "title": "Les métiers et les milieux de l’art"
    },
    {
      "description": "Comment la suite du cours va aider à regarder les œuvres avec plus de précision, à reconnaître des styles, à replacer l’art dans son époque et à suivre les grandes questions qui traversent l’histoire visuelle.",
      "title": "Ce que la suite du cours va apporter"
    }
  ]
}
